### Create Collections and Insert Sample Data in C

Source: https://github.com/mongodb/docs/blob/main/content/manual/manual/source/includes/aggregation/aggregation-examples/one-to-one-join/c-one-to-one-join.rst

Use this snippet to initialize the 'orders' and 'products' collections and populate them with sample documents required for the one-to-one join example.

```c
   /* Create the orders collection and insert sample data */
   {
      bson_t *doc;
      bson_error_t error;
      mongoc_collection_t *orders_collection = mongoc_client_get_collection (client, ""testdb"", ""orders"");
      mongoc_collection_t *products_collection = mongoc_client_get_collection (client, ""testdb"", ""products"");

      doc = BCON_NEW (""_id"", BCON_INT32 (1), ""product_id"", BCON_INT32 (100), ""order_date"", BCON_DATE_TIME (1577836800000LL)); // Jan 1, 2020
      if (!mongoc_collection_insert_one (orders_collection, doc, NULL, NULL, &error)) {
         fprintf (stderr, ""Insert failed: %s\n"", error.message);
         goto cleanup;
      }
      bson_destroy (doc);

      doc = BCON_NEW (""_id"", BCON_INT32 (2), ""product_id"", BCON_INT32 (101), ""order_date"", BCON_DATE_TIME (1580515200000LL)); // Feb 1, 2020
      if (!mongoc_collection_insert_one (orders_collection, doc, NULL, NULL, &error)) {
         fprintf (stderr, ""Insert failed: %s\n"", error.message);
         goto cleanup;
      }
      bson_destroy (doc);

      doc = BCON_NEW (""_id"", BCON_INT32 (3), ""product_id"", BCON_INT32 (100), ""order_date"", BCON_DATE_TIME (1609459200000LL)); // Jan 1, 2021
      if (!mongoc_collection_insert_one (orders_collection, doc, NULL, NULL, &error)) {
         fprintf (stderr, ""Insert failed: %s\n"", error.message);
         goto cleanup;
      }
      bson_destroy (doc);

      doc = BCON_NEW (""_id"", BCON_INT32 (100), ""name"", BCON_UTF8 (""Laptop""), ""category"", BCON_UTF8 (""Electronics""));
      if (!mongoc_collection_insert_one (products_collection, doc, NULL, NULL, &error)) {
         fprintf (stderr, ""Insert failed: %s\n"", error.message);
         goto cleanup;
      }
      bson_destroy (doc);

      doc = BCON_NEW (""_id"", BCON_INT32 (101), ""name"", BCON_UTF8 (""Mouse""), ""category"", BCON_UTF8 (""Electronics""));
      if (!mongoc_collection_insert_one (products_collection, doc, NULL, NULL, &error)) {
         fprintf (stderr, ""Insert failed: %s\n"", error.message);
         goto cleanup;
      }
      bson_destroy (doc);

      mongoc_collection_destroy (orders_collection);
      mongoc_collection_destroy (products_collection);
   }
```

